Code:
public int makeChocolate(int small, int big, int goal) {
    int bigCount = goal / 5;
    int remaining = goal % 5;
    if (bigCount > big) {
        bigCount = big;
        remaining = goal - bigCount * 5;
    }

    if (remaining > small) {
        return -1;
    } else {
        return remaining;
    }
}

public int makeChocolate(int small, int big, int goal) {
    if (big * 5 > goal) {
        int maxBig = goal / 5;
        if (maxBig > big) maxBig = big;
        goal -= maxBig * 5;
        if (goal > small) return -1;
        return goal;
    } else {
        goal -= big * 5;
        if (goal > small) return -1;
        return goal;
    }
}

